// AddLastMessageConversations adds the given related objects to the existing relationships
// of the message, optionally inserting them as new records.
// Appends related to o.R.LastMessageConversations.
// Sets related.R.LastMessage appropriately.
func (o *Message) AddLastMessageConversations(ctx context.Context, exec boil.ContextExecutor, insert bool, related ...*Conversation) error {
	var err error
	for _, rel := range related {
		if insert {
			queries.Assign(&rel.LastMessageID, o.ID)
			if err = rel.Insert(ctx, exec, boil.Infer()); err != nil {
				return errors.Wrap(err, "failed to insert into foreign table")
			}
		} else {
			updateQuery := fmt.Sprintf(
				"UPDATE \"conversations\" SET %s WHERE %s",
				strmangle.SetParamNames("\"", "\"", 1, []string{"last_message_id"}),
				strmangle.WhereClause("\"", "\"", 2, conversationPrimaryKeyColumns),
			)
			values := []interface{}{o.ID, rel.ID}

			if boil.IsDebug(ctx) {
				writer := boil.DebugWriterFrom(ctx)
				fmt.Fprintln(writer, updateQuery)
				fmt.Fprintln(writer, values)
			}
			if _, err = exec.ExecContext(ctx, updateQuery, values...); err != nil {
				return errors.Wrap(err, "failed to update foreign table")
			}

			queries.Assign(&rel.LastMessageID, o.ID)
		}
	}

	if o.R == nil {
		o.R = &messageR{
			LastMessageConversations: related,
		}
	} else {
		o.R.LastMessageConversations = append(o.R.LastMessageConversations, related...)
	}

	for _, rel := range related {
		if rel.R == nil {
			rel.R = &conversationR{
				LastMessage: o,
			}
		} else {
			rel.R.LastMessage = o
		}
	}
	return nil
}

// SetLastMessageConversations removes all previously related items of the
// message replacing them completely with the passed
// in related items, optionally inserting them as new records.
// Sets o.R.LastMessage's LastMessageConversations accordingly.
// Replaces o.R.LastMessageConversations with related.
// Sets related.R.LastMessage's LastMessageConversations accordingly.
func (o *Message) SetLastMessageConversations(ctx context.Context, exec boil.ContextExecutor, insert bool, related ...*Conversation) error {
	query := "update \"conversations\" set \"last_message_id\" = null where \"last_message_id\" = $1"
	values := []interface{}{o.ID}
	if boil.IsDebug(ctx) {
		writer := boil.DebugWriterFrom(ctx)
		fmt.Fprintln(writer, query)
		fmt.Fprintln(writer, values)
	}
	_, err := exec.ExecContext(ctx, query, values...)
	if err != nil {
		return errors.Wrap(err, "failed to remove relationships before set")
	}

	if o.R != nil {
		for _, rel := range o.R.LastMessageConversations {
			queries.SetScanner(&rel.LastMessageID, nil)
			if rel.R == nil {
				continue
			}

			rel.R.LastMessage = nil
		}
		o.R.LastMessageConversations = nil
	}

	return o.AddLastMessageConversations(ctx, exec, insert, related...)
}

// RemoveLastMessageConversations relationships from objects passed in.
// Removes related items from R.LastMessageConversations (uses pointer comparison, removal does not keep order)
// Sets related.R.LastMessage.
func (o *Message) RemoveLastMessageConversations(ctx context.Context, exec boil.ContextExecutor, related ...*Conversation) error {
	if len(related) == 0 {
		return nil
	}

	var err error
	for _, rel := range related {
		queries.SetScanner(&rel.LastMessageID, nil)
		if rel.R != nil {
			rel.R.LastMessage = nil
		}
		if _, err = rel.Update(ctx, exec, boil.Whitelist("last_message_id")); err != nil {
			return err
		}
	}
	if o.R == nil {
		return nil
	}

	for _, rel := range related {
		for i, ri := range o.R.LastMessageConversations {
			if rel != ri {
				continue
			}

			ln := len(o.R.LastMessageConversations)
			if ln > 1 && i < ln-1 {
				o.R.LastMessageConversations[i] = o.R.LastMessageConversations[ln-1]
			}
			o.R.LastMessageConversations = o.R.LastMessageConversations[:ln-1]
			break
		}
	}

	return nil
}

